import { test, expect } from '@playwright/test';

test('Amazon SG - Search monitor, navigate to product, back, validate results', async ({ page }) => {
  // 1. Launch browser → Amazon SG.
  await page.goto('https://www.amazon.sg/', { waitUntil: 'domcontentloaded' });

  // Accept cookies if banner appears (optional, for robustness)
  const acceptCookies = page.getByRole('button', { name: /accept cookies/i });
  if (await acceptCookies.isVisible({ timeout: 2000 }).catch(() => false)) {
    await acceptCookies.click();
  }

  // 2. Search for "monitor".
  const searchBox = page.locator('input#twotabsearchtextbox');
  await expect(searchBox).toBeVisible({ timeout: 10000 });
  await searchBox.fill('monitor');
  await page.getByRole('button', { name: /search/i }).click();

  // 3. Click first product.
  const firstProduct = page.locator('div.s-main-slot div[data-component-type="s-search-result"]')
    .first()
    .locator('h2 a[href]');
  await expect(firstProduct).toBeVisible({ timeout: 10000 });
  await firstProduct.click();

  // 4. Click browser back button.
  await page.goBack();

  // 5. Validate search results page is displayed.
  // Wait for the search box with value 'monitor' and results list
  await expect(page.locator('input#twotabsearchtextbox')).toHaveValue('monitor', { timeout: 10000 });
  await expect(page.locator('div.s-main-slot div[data-component-type="s-search-result"]')).toBeVisible();

  // 6. Close browser. (Playwright test runner handles this automatically)
});
